import React, { useEffect, useState } from "react";
import Favicon from "../../assets/favicon.svg";

const Hwd = () => {
  const iconUrls = Array(11).fill(Favicon); // Simplified array creation

  // Calculate positions based on container size
  const calculatePositions = (width: number, height: number) => {
    const corners = [
      { x: width * 0.166, y: 0 }, // top-left (1/6 of width)
      { x: width * 0.833, y: 0 }, // top-right (5/6 of width)
      { x: width, y: height }, // bottom-right
      { x: 0, y: height }, // bottom-left
    ];

    const topIcons = Array.from({ length: 3 }).map((_, i) => ({
      x: corners[0].x + ((i + 1) * (corners[1].x - corners[0].x)) / 4,
      y: 0,
    }));

    const bottomIcons = Array.from({ length: 4 }).map((_, i) => ({
      x: ((i + 1) * width) / 5,
      y: height,
    }));

    return [
      corners[0],
      ...topIcons,
      corners[1], // Top side (0-4)
      corners[2],
      ...bottomIcons,
      corners[3], // Bottom side (5-10)
    ];
  };

  const [containerSize, setContainerSize] = useState({
    width: 900,
    height: 160,
  });
  const [activeIndex, setActiveIndex] = useState(0);
  const containerRef = React.useRef<HTMLDivElement>(null);

  // Handle resize
  useEffect(() => {
    const updateSize = () => {
      if (containerRef.current) {
        const maxWidth = Math.min(window.innerWidth * 0.9, 900);
        const height = maxWidth * (160 / 900); // Maintain aspect ratio
        setContainerSize({ width: maxWidth, height });
      }
    };

    updateSize();
    window.addEventListener("resize", updateSize);
    return () => window.removeEventListener("resize", updateSize);
  }, []);

  // Animation interval
  useEffect(() => {
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % 11); // 11 total icons
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  const allIcons = calculatePositions(
    containerSize.width,
    containerSize.height
  );

  return (
    <div
      id="how_we_do"
      className="w-full max-w-[1440px] mx-auto py-8 md:py-12 lg:py-16"
    >
      <h1 className="text-center text-2xl sm:text-3xl md:text-[30px] lg:text-[35px] xl:text-[40px] font-black leading-tight text-white px-4">
        Streamline processes with
        <br />
        smart integrations
      </h1>

      <div className="mt-8 md:mt-12 lg:mt-16 xl:mt-20 flex justify-center">
        <div
          ref={containerRef}
          className="relative w-full max-w-[900px]"
          style={{ height: `${containerSize.height}px` }}
        >
          <svg
            width="100%"
            height="100%"
            viewBox={`0 0 ${containerSize.width} ${containerSize.height}`}
            preserveAspectRatio="xMidYMid meet"
          >
            {/* Top edge */}
            <line
              x1={allIcons[0].x}
              y1={allIcons[0].y}
              x2={allIcons[4].x}
              y2={allIcons[4].y}
              stroke="gray"
              strokeWidth={4}
            />
            {/* Right edge */}
            <line
              x1={allIcons[4].x}
              y1={allIcons[4].y}
              x2={allIcons[5].x}
              y2={allIcons[5].y}
              stroke="gray"
              strokeWidth={2}
            />
            {/* Bottom edge */}
            <line
              x1={allIcons[5].x}
              y1={allIcons[5].y}
              x2={allIcons[10].x}
              y2={allIcons[10].y}
              stroke="gray"
              strokeWidth={4}
            />
            {/* Left edge */}
            <line
              x1={allIcons[10].x}
              y1={allIcons[10].y}
              x2={allIcons[0].x}
              y2={allIcons[0].y}
              stroke="gray"
              strokeWidth={2}
            />
          </svg>

          {allIcons.map(({ x, y }, i) => {
            const isActive = (() => {
              const topIndices = [0, 1, 2, 3, 4];
              const bottomRightCorner = 5;
              const bottomSideIcons = [6, 7, 8, 9];
              const bottomLeftCorner = 10;
              const totalCycle =
                topIndices.length + 1 + bottomSideIcons.length + 1;
              const cyclePos = activeIndex % totalCycle;

              if (cyclePos < topIndices.length) {
                return i === topIndices[cyclePos];
              } else if (cyclePos === topIndices.length) {
                return i === bottomRightCorner;
              } else if (
                cyclePos <
                topIndices.length + 1 + bottomSideIcons.length
              ) {
                const reversedBottom = [...bottomSideIcons].reverse();
                return i === reversedBottom[cyclePos - topIndices.length - 1];
              } else {
                return i === bottomLeftCorner;
              }
            })();

            const iconSize = Math.min(containerSize.width * 0.1, 90); // Responsive icon size

            return (
              <div
                key={`icon-${i}`}
                className="absolute transition-all duration-500 ease-in-out"
                style={{
                  width: `${iconSize}px`,
                  height: `${iconSize}px`,
                  left: `${x - iconSize / 2}px`,
                  top: `${y - iconSize / 2}px`,
                  padding: "7px",
                  backgroundColor: "darkgray",
                  borderRadius: "50%",
                  filter: isActive ? "none" : "grayscale(100%) saturate(0%)",
                  transform: isActive ? "scale(1.1)" : "scale(1)",
                }}
              >
                <img
                  src={iconUrls[i]}
                  alt={`icon-${i}`}
                  className="w-full h-full object-contain"
                  draggable={false}
                />
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

export default Hwd;
